def gen(rng, size):
    side = max(1, min(60, int(size ** 0.5) + 1))
    rows = rng.randint(1, side)
    cols = rng.randint(1, side)
    grid = []
    for _ in range(rows):
        row = []
        for _ in range(cols):
            x = rng.random()
            if x < 0.4:
                row.append('#')
            elif x < 0.6:
                row.append('*')
            else:
                row.append('.')
        grid.append(row)
    return [grid]

