class Solution:
    def rotateTheBox(self, boxGrid):
        rows = len(boxGrid)
        cols = len(boxGrid[0])
        g = [row[:] for row in boxGrid]
        for r in range(rows):
            # settle stones to the right, repeatedly bubbling each stone past empties
            moved = True
            while moved:
                moved = False
                for c in range(cols - 1):
                    if g[r][c] == '#' and g[r][c + 1] == '.':
                        g[r][c] = '.'
                        g[r][c + 1] = '#'
                        moved = True
        res = [['' for _ in range(rows)] for _ in range(cols)]
        for r in range(rows):
            for c in range(cols):
                res[c][rows - 1 - r] = g[r][c]
        return res

