class Solution:
    def rotateTheBox(self, boxGrid):
        rows = len(boxGrid)
        cols = len(boxGrid[0])
        g = [row[:] for row in boxGrid]
        for r in range(rows):
            write = cols - 1
            for c in range(cols - 1, -1, -1):
                if g[r][c] == '*':
                    write = c - 1
                elif g[r][c] == '#':
                    g[r][c] = '.'
                    g[r][write] = '#'
                    write -= 1
        res = [[None] * rows for _ in range(cols)]
        for r in range(rows):
            for c in range(cols):
                res[c][rows - 1 - r] = g[r][c]
        return res

