var rotateTheBox = function(boxGrid) {
    const rows = boxGrid.length, cols = boxGrid[0].length;
    const g = boxGrid.map(row => row.slice());
    for (let r = 0; r < rows; r++) {
        let write = cols - 1;
        for (let c = cols - 1; c >= 0; c--) {
            if (g[r][c] === '*') {
                write = c - 1;
            } else if (g[r][c] === '#') {
                g[r][c] = '.';
                g[r][write] = '#';
                write--;
            }
        }
    }
    const res = Array.from({length: cols}, () => new Array(rows).fill(null));
    for (let r = 0; r < rows; r++) {
        for (let c = 0; c < cols; c++) {
            res[c][rows - 1 - r] = g[r][c];
        }
    }
    return res;
};
